/* ===== js/utils/stateSerializer.js ===== */
/**
 * Safe state serializer for app state persisted in local storage.
 * Supports Set, Map, and Date while bounding recursive structures and
 * dropping prototype-pollution keys during serialization and restore.
 */
const STATE_SERIALIZER_POLLUTION_KEYS = new Set(['__proto__', 'prototype', 'constructor']);
const STATE_SERIALIZER_MAX_DEPTH = 32;
const STATE_SERIALIZER_MAX_NODES = 50000;
const STATE_SERIALIZER_MAX_ARRAY_ITEMS = 5000;
const STATE_SERIALIZER_MAX_OBJECT_KEYS = 500;
const STATE_SERIALIZER_MAX_COLLECTION_ITEMS = 5000;

class StateSerializer {
    static serialize(value) {
        return StateSerializer._serialize(value, {
            nodes: 0,
            stack: new WeakSet()
        }, 0);
    }

    static deserialize(value) {
        return StateSerializer._deserialize(value, {
            nodes: 0,
            stack: new WeakSet()
        }, 0);
    }

    static _serialize(value, state, depth) {
        if (value === null || value === undefined) {
            return value;
        }
        if (typeof value !== 'object') {
            return value;
        }
        if (!StateSerializer.enterTraversal(value, state, depth, 'serialize')) {
            return null;
        }

        try {
            if (value instanceof Set) {
                return {
                    __type: 'Set',
                    __value: Array.from(value)
                        .slice(0, STATE_SERIALIZER_MAX_COLLECTION_ITEMS)
                        .map((item) => StateSerializer._serialize(item, state, depth + 1))
                };
            }

            if (value instanceof Map) {
                return {
                    __type: 'Map',
                    __value: Array.from(value.entries())
                        .slice(0, STATE_SERIALIZER_MAX_COLLECTION_ITEMS)
                        .map(([key, item]) => [
                            StateSerializer._serialize(key, state, depth + 1),
                            StateSerializer._serialize(item, state, depth + 1)
                        ])
                };
            }

            if (value instanceof Date) {
                return {
                    __type: 'Date',
                    __value: Number.isNaN(value.getTime()) ? null : value.toISOString()
                };
            }

            if (Array.isArray(value)) {
                return value
                    .slice(0, STATE_SERIALIZER_MAX_ARRAY_ITEMS)
                    .map((item) => StateSerializer._serialize(item, state, depth + 1));
            }

            const serialized = {};
            for (const [key, item] of StateSerializer.safeEntries(value).slice(0, STATE_SERIALIZER_MAX_OBJECT_KEYS)) {
                const safeValue = StateSerializer._serialize(item, state, depth + 1);
                if (safeValue !== undefined) {
                    serialized[key] = safeValue;
                }
            }
            return serialized;
        } finally {
            StateSerializer.exitTraversal(value, state);
        }
    }

    static _deserialize(value, state, depth) {
        if (value === null || value === undefined) {
            return value;
        }
        if (typeof value !== 'object') {
            return value;
        }
        if (!StateSerializer.enterTraversal(value, state, depth, 'deserialize')) {
            return null;
        }

        try {
            if (Object.prototype.hasOwnProperty.call(value, '__type')) {
                const type = typeof value.__type === 'string' ? value.__type : '';
                if (type === 'Set') {
                    return new Set(
                        StateSerializer.normalizeArray(value.__value, STATE_SERIALIZER_MAX_COLLECTION_ITEMS)
                            .map((item) => StateSerializer._deserialize(item, state, depth + 1))
                    );
                }
                if (type === 'Map') {
                    return new Map(
                        StateSerializer.normalizeArray(value.__value, STATE_SERIALIZER_MAX_COLLECTION_ITEMS)
                            .filter((entry) => Array.isArray(entry) && entry.length >= 2)
                            .map(([key, item]) => [
                                StateSerializer._deserialize(key, state, depth + 1),
                                StateSerializer._deserialize(item, state, depth + 1)
                            ])
                    );
                }
                if (type === 'Date') {
                    if (typeof value.__value !== 'string') {
                        return null;
                    }
                    const date = new Date(value.__value);
                    return Number.isNaN(date.getTime()) ? null : date;
                }
                console.warn(`[StateSerializer] Unknown type: ${type}`);
                return StateSerializer._deserialize(value.__value, state, depth + 1);
            }

            if (Array.isArray(value)) {
                return value
                    .slice(0, STATE_SERIALIZER_MAX_ARRAY_ITEMS)
                    .map((item) => StateSerializer._deserialize(item, state, depth + 1));
            }

            const deserialized = {};
            for (const [key, item] of StateSerializer.safeEntries(value).slice(0, STATE_SERIALIZER_MAX_OBJECT_KEYS)) {
                const safeValue = StateSerializer._deserialize(item, state, depth + 1);
                if (safeValue !== undefined) {
                    deserialized[key] = safeValue;
                }
            }
            return deserialized;
        } finally {
            StateSerializer.exitTraversal(value, state);
        }
    }

    static enterTraversal(value, state, depth, operation) {
        if (depth > STATE_SERIALIZER_MAX_DEPTH) {
            throw new Error(`State is too deeply nested to ${operation} safely. Maximum supported depth is ${STATE_SERIALIZER_MAX_DEPTH}.`);
        }
        if (state.stack.has(value)) {
            return false;
        }
        state.stack.add(value);
        state.nodes += 1;
        if (state.nodes > STATE_SERIALIZER_MAX_NODES) {
            throw new Error(`State is too large to ${operation} safely. Maximum supported node count is ${STATE_SERIALIZER_MAX_NODES}.`);
        }
        return true;
    }

    static exitTraversal(value, state) {
        state.stack.delete(value);
    }

    static isUnsafeKey(key) {
        return STATE_SERIALIZER_POLLUTION_KEYS.has(String(key));
    }

    static safeEntries(value) {
        if (!value || typeof value !== 'object' || Array.isArray(value)) {
            return [];
        }
        return Object.entries(value).filter(([key]) => !StateSerializer.isUnsafeKey(key));
    }

    static normalizeArray(value, limit = STATE_SERIALIZER_MAX_ARRAY_ITEMS) {
        return Array.isArray(value) ? value.slice(0, limit) : [];
    }

    static validate(originalValue) {
        try {
            const serialized = StateSerializer.serialize(originalValue);
            const deserialized = StateSerializer.deserialize(serialized);

            if (originalValue instanceof Set) {
                const originalArray = Array.from(originalValue);
                const deserializedArray = Array.from(deserialized);
                return JSON.stringify(originalArray.sort()) === JSON.stringify(deserializedArray.sort());
            }

            if (originalValue instanceof Map) {
                const originalArray = Array.from(originalValue.entries()).sort();
                const deserializedArray = Array.from(deserialized.entries()).sort();
                return JSON.stringify(originalArray) === JSON.stringify(deserializedArray);
            }

            return JSON.stringify(originalValue) === JSON.stringify(deserialized);
        } catch (error) {
            console.error('[StateSerializer] Validation failed:', error);
            return false;
        }
    }

    static createStorageAdapter(baseStorage) {
        return {
            async get(key, defaultValue = null) {
                try {
                    const value = await baseStorage.get(key, defaultValue);
                    return StateSerializer.deserialize(value);
                } catch (error) {
                    console.error(`[StateSerializer] get failed ${key}:`, error);
                    return defaultValue;
                }
            },

            async set(key, value) {
                try {
                    const serializedValue = StateSerializer.serialize(value);
                    return await baseStorage.set(key, serializedValue);
                } catch (error) {
                    console.error(`[StateSerializer] set failed ${key}:`, error);
                    throw error;
                }
            },

            async remove(key) {
                try {
                    return await baseStorage.remove(key);
                } catch (error) {
                    console.error(`[StateSerializer] remove failed ${key}:`, error);
                    throw error;
                }
            },

            async clear() {
                try {
                    return await baseStorage.clear();
                } catch (error) {
                    console.error('[StateSerializer] clear failed:', error);
                    throw error;
                }
            }
        };
    }
}

if (typeof module !== 'undefined' && module.exports) {
    module.exports = StateSerializer;
}


/* ===== js/utils/simpleStorageWrapper.js ===== */
(function(window) {
    class SimpleStorageWrapper {
        constructor(repositories) {
            this.repos = repositories;
        }

        get practiceRepo() { return this.repos.practice; }
        get settingsRepo() { return this.repos.settings; }
        get backupRepo() { return this.repos.backups; }
        get metaRepo() { return this.repos.meta; }

        async getPracticeRecords() {
            if (window.PracticeCore && window.PracticeCore.store && typeof window.PracticeCore.store.listPracticeRecords === 'function') {
                return await window.PracticeCore.store.listPracticeRecords();
            }
            return await this.practiceRepo.list();
        }
        async savePracticeRecords(records) {
            if (window.PracticeCore && window.PracticeCore.store && typeof window.PracticeCore.store.replacePracticeRecords === 'function') {
                return await window.PracticeCore.store.replacePracticeRecords(records, { maxRecords: this.practiceRepo.maxRecords || 1000 });
            }
            await this.practiceRepo.overwrite(records);
            return true;
        }
        async addPracticeRecord(record) {
            if (window.PracticeCore && window.PracticeCore.store && typeof window.PracticeCore.store.savePracticeRecord === 'function') {
                await window.PracticeCore.store.savePracticeRecord(record, { maxRecords: this.practiceRepo.maxRecords || 1000 });
                return true;
            }
            await this.practiceRepo.upsert(record);
            return true;
        }
        async getById(id) { return await this.practiceRepo.getById(id); }
        async update(id, updates) { return await this.practiceRepo.update(id, updates); }
        async delete(id) { const removed = await this.practiceRepo.removeById(id); return removed > 0; }
        async deletePracticeRecord(id) { return await this.delete(id); }
        async deletePracticeRecords(ids) { return await this.practiceRepo.removeByIds(ids); }
        async getPracticeRecordsCount() { return await this.practiceRepo.count(); }
        validatePracticeRecord(record) { return this.practiceRepo.validatePracticeRecord(record); }

        async getUserSettings() { return await this.settingsRepo.getAll(); }
        async saveUserSettings(settings) { await this.settingsRepo.saveAll(settings); return true; }
        async getUserSetting(key, defaultValue = null) { return await this.settingsRepo.get(key, defaultValue); }
        async setUserSetting(key, value) { await this.settingsRepo.set(key, value); return true; }

        async getBackups() { return await this.backupRepo.list(); }
        async saveBackups(backups) { await this.backupRepo.saveAll(backups); return true; }
        async addBackup(backup) { await this.backupRepo.add(backup); return true; }
        async deleteBackup(id) { return await this.backupRepo.delete(id); }
        async clearBackups() { await this.backupRepo.clear(); return true; }

        async get(key, defaultValue = null) { return await this.metaRepo.get(key, defaultValue); }
        async set(key, value) { await this.metaRepo.set(key, value); return true; }
        async remove(key) { await this.metaRepo.remove(key); return true; }
    }

    function connectWrapper(repositories) {
        if (!repositories) {
            return;
        }
        if (window.simpleStorageWrapper && window.simpleStorageWrapper.repos === repositories) {
            return;
        }
        window.simpleStorageWrapper = new SimpleStorageWrapper(repositories);
        console.log('[SimpleStorageWrapper] 已连接新的数据仓库接口');
    }

    const registry = window.StorageProviderRegistry;
    if (registry && typeof registry.onProvidersReady === 'function') {
        registry.onProvidersReady(({ repositories }) => connectWrapper(repositories));
        const current = registry.getCurrentProviders && registry.getCurrentProviders();
        if (current && current.repositories) {
            connectWrapper(current.repositories);
        }
    } else if (window.dataRepositories) {
        connectWrapper(window.dataRepositories);
    } else {
        console.warn('[SimpleStorageWrapper] 数据仓库尚未可用，等待外部注入');
    }

    window.SimpleStorageWrapper = SimpleStorageWrapper;
})(window);


